import { LOGO_SRC } from '../constants/brand';
import './Logo.css';

const SIZES = {
  xs: 28,
  sm: 36,
  md: 44,
  lg: 88,
  xl: 120,
};

export default function Logo({ size = 'md', className = '', avatar = false }) {
  return (
    <img
      src={LOGO_SRC}
      alt="Very Direct"
      className={['logo', `logo--${size}`, avatar && 'logo--avatar', className].filter(Boolean).join(' ')}
      style={{ height: SIZES[size] || SIZES.md }}
    />
  );
}
